"use client";

import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";
import { getRequisitions } from "@/lib/requisitions";
import { getSpendAnalytics } from "@/lib/analytics";
import { SpendBarChart, BudgetDonutChart } from "@/components/charts/SimpleCharts";
import { formatCurrency } from "@/lib/currencies";
import Link from "next/link";

export default function Dashboard() {
    const { user } = useAuth();
    const router = useRouter();
    const [stats, setStats] = useState({
        pendingCount: 0,
        activeCount: 0,
        totalSpend: 0,
        monthlyData: [] as any[]
    });

    useEffect(() => {
        const loadData = async () => {
            const [reqs, analytics] = await Promise.all([
                getRequisitions(),
                getSpendAnalytics()
            ]);

            const pending = reqs.filter(r => r.status === 'PENDING').length;

            // Mocking monthly data for visualization since backend might just have total
            const mockMonthly = [
                { label: 'Jan', value: 12000 },
                { label: 'Feb', value: 19500 },
                { label: 'Mar', value: 15000 },
                { label: 'Apr', value: 28000 }, // Current month (high)
                { label: 'May', value: 0 },
                { label: 'Jun', value: 0 },
            ];

            setStats({
                pendingCount: pending,
                activeCount: reqs.length,
                totalSpend: analytics.totalSpend,
                monthlyData: mockMonthly
            });
        };
        loadData();
    }, []);

    const quickActions = [
        { name: "New Request", href: "/dashboard/requisitions/new", icon: "📝", color: "var(--accent)" },
        { name: "Approve Requests", href: "/dashboard/approvals", icon: "✅", color: "var(--success)" },
        { name: "Check Budget", href: "/dashboard/budgets", icon: "💰", color: "#eab308" }, // Warning/Yellow
    ];

    return (
        <div>
            {/* Greeting Section */}
            <div style={{ marginBottom: '2rem', animation: 'fadeIn 0.8s ease-out' }}>
                <h1 style={{
                    fontSize: '2.5rem',
                    fontWeight: 800,
                    marginBottom: '0.5rem',
                    background: 'linear-gradient(135deg, var(--text-main) 0%, var(--text-secondary) 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    letterSpacing: '-0.03em'
                }}>
                    Good Afternoon, {user?.displayName?.split(' ')[0] || 'User'} 👋
                </h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1.1rem' }}>Here's what's happening with your spend today.</p>
            </div>

            {/* Stats Grid */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '1.5rem', marginBottom: '2rem' }}>
                <DashboardCard
                    title="Total Spend (YTD)"
                    value={formatCurrency(stats.totalSpend, 'USD')}
                    icon="💰" trend="+12%"
                />
                <DashboardCard
                    title="Pending Approvals"
                    value={stats.pendingCount.toString()}
                    icon="⏳"
                    urgent={stats.pendingCount > 0}
                />
                <DashboardCard
                    title="Active Requests"
                    value={stats.activeCount.toString()}
                    icon="📝"
                />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
                {/* Main Chart Section */}
                <div className="card">
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <h2 style={{ fontSize: '1.1rem', fontWeight: 'bold' }}>Spend Trends</h2>
                        <select style={{ padding: '0.25rem', border: '1px solid var(--border)', borderRadius: '4px' }}>
                            <option>Last 6 Months</option>
                            <option>Year to Date</option>
                        </select>
                    </div>
                    <SpendBarChart data={stats.monthlyData} />
                </div>

                {/* Side Section: Quick Actions & Budget Health */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                    {/* Budget Health */}
                    <div className="card" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                        <div>
                            <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.25rem' }}>Overall Budget</h3>
                            <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>FY 2026</p>
                        </div>
                        <BudgetDonutChart total={100000} used={stats.totalSpend || 45000} />
                    </div>

                    {/* Quick Actions */}
                    <div className="card">
                        <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '1rem' }}>Quick Actions</h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                            {quickActions.map(action => (
                                <Link
                                    href={action.href}
                                    key={action.name}
                                    style={{
                                        display: 'flex', alignItems: 'center', gap: '1rem',
                                        padding: '0.75rem', borderRadius: 'var(--radius-md)',
                                        backgroundColor: 'var(--background)',
                                        transition: 'transform 0.2s',
                                        fontSize: '0.9rem',
                                        fontWeight: 500
                                    }}
                                >
                                    <span style={{ color: action.color, fontSize: '1.2rem' }}>{action.icon}</span>
                                    {action.name}
                                </Link>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function DashboardCard({ title, value, icon, trend, urgent }: { title: string, value: string, icon: string, trend?: string, urgent?: boolean }) {
    return (
        <div className="card" style={{
            display: 'flex', alignItems: 'center', gap: '1rem',
            borderLeft: urgent ? '4px solid var(--warning)' : '1px solid var(--border)'
        }}>
            <div style={{
                width: '48px',
                height: '48px',
                borderRadius: 'var(--radius-md)',
                backgroundColor: urgent ? '#fef3c7' : 'var(--background)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '1.5rem'
            }}>
                {icon}
            </div>
            <div>
                <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>{title}</div>
                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--primary)' }}>{value}</div>
                {trend && <div style={{ fontSize: '0.75rem', color: 'var(--success)' }}>{trend} vs last month</div>}
            </div>
        </div>
    );
}
